API_name: school_calendar_get_upcoming
Description:
{
  "description": "取得即將到來的行事曆事件（未來N天內）",
  "required_parameters": [],
  "optional_parameters": [
    {
      "name": "days",
      "type": "NUMBER",
      "description": "往後查詢幾天",
      "default": 30
    },
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "最多回傳幾筆結果",
      "default": 20
    }
  ]
}

